"use client"

import { AdminLayout } from "@/components/admin-layout"
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card"
import { mockDeals } from "@/lib/mock-data"
import { useParams, useRouter } from "next/navigation"
import { Button } from "@/components/ui/button"
import { ArrowLeft } from "lucide-react"

export default function DealDetailsPage() {
  const params = useParams()
  const router = useRouter()
  const dealId = params.id as string
  const deal = mockDeals.find((d) => d.id === dealId)

  if (!deal) {
    return (
      <AdminLayout>
        <div className="p-8 text-center">
          <p className="text-muted-foreground">Deal not found</p>
        </div>
      </AdminLayout>
    )
  }

  const avgCompPrice = deal.comps.reduce((sum, c) => sum + c.price, 0) / deal.comps.length

  return (
    <AdminLayout>
      <div className="p-8 space-y-6">
        <div className="flex items-center gap-4">
          <Button variant="ghost" size="icon" onClick={() => router.back()}>
            <ArrowLeft className="w-4 h-4" />
          </Button>
          <div>
            <h1 className="text-3xl font-bold text-foreground">{deal.address}</h1>
            <p className="text-muted-foreground">Analyzed on {deal.createdDate}</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium">Purchase Price</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">${deal.price.toLocaleString()}</div>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium">After Repair Value</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold">${deal.arv.toLocaleString()}</div>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm font-medium">Profit Margin</CardTitle>
            </CardHeader>
            <CardContent>
              <div className={`text-2xl font-bold ${deal.profitPercent >= 0 ? "text-success" : "text-destructive"}`}>
                {deal.profitPercent}%
              </div>
            </CardContent>
          </Card>
        </div>

        <Card>
          <CardHeader>
            <CardTitle>Comparable Sales (COMPs)</CardTitle>
            <CardDescription>Market analysis using comparable properties</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-border">
                    <th className="text-left py-3 px-4 font-semibold text-sm text-muted-foreground">Address</th>
                    <th className="text-right py-3 px-4 font-semibold text-sm text-muted-foreground">Price</th>
                    <th className="text-right py-3 px-4 font-semibold text-sm text-muted-foreground">DOM</th>
                    <th className="text-right py-3 px-4 font-semibold text-sm text-muted-foreground">Distance</th>
                  </tr>
                </thead>
                <tbody>
                  {deal.comps.map((comp) => (
                    <tr key={comp.address} className="border-b border-border hover:bg-muted/50">
                      <td className="py-3 px-4 text-sm">{comp.address}</td>
                      <td className="text-right py-3 px-4 text-sm">${comp.price.toLocaleString()}</td>
                      <td className="text-right py-3 px-4 text-sm">{comp.dom} days</td>
                      <td className="text-right py-3 px-4 text-sm">{comp.distance} mi</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            <div className="mt-4 p-4 bg-muted rounded-lg">
              <p className="text-sm">
                <span className="font-semibold">Average COMP Price:</span> ${avgCompPrice.toLocaleString()}
              </p>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>ARV Adjustments</CardTitle>
            <CardDescription>Breakdown of value adjustments</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              {deal.arvAdjustments.map((adj, idx) => (
                <div key={idx} className="p-4 border border-border rounded-lg">
                  <div className="flex items-center justify-between mb-2">
                    <p className="font-semibold">{adj.category}</p>
                    <p className={`font-bold ${adj.amount >= 0 ? "text-success" : "text-destructive"}`}>
                      {adj.amount >= 0 ? "+" : ""}${Math.abs(adj.amount).toLocaleString()}
                    </p>
                  </div>
                  <p className="text-sm text-muted-foreground">{adj.reason}</p>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>DOM Gating Analysis</CardTitle>
            <CardDescription>Days on Market evaluation</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              <div>
                <p className="text-sm text-muted-foreground">DOM Threshold</p>
                <p className="text-2xl font-bold">{deal.domGatingThreshold} days</p>
              </div>
              <div className="p-4 bg-muted rounded-lg">
                <p className="text-sm">
                  All comparable properties meet DOM gating requirements with DOMs ranging from{" "}
                  {Math.min(...deal.comps.map((c) => c.dom))} to {Math.max(...deal.comps.map((c) => c.dom))} days.
                </p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle>Decision</CardTitle>
          </CardHeader>
          <CardContent>
            <div
              className={`p-6 rounded-lg border-2 ${
                deal.status === "PASS" ? "border-success/50 bg-success/5" : "border-destructive/50 bg-destructive/5"
              }`}
            >
              <p className={`text-2xl font-bold mb-3 ${deal.status === "PASS" ? "text-success" : "text-destructive"}`}>
                {deal.status}
              </p>
              {deal.failureReasons && deal.failureReasons.length > 0 && (
                <div className="space-y-2">
                  <p className="font-semibold text-sm mb-2">Failure Reasons:</p>
                  <ul className="list-disc list-inside space-y-1">
                    {deal.failureReasons.map((reason, idx) => (
                      <li key={idx} className="text-sm text-muted-foreground">
                        {reason}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
              {deal.status === "PASS" && (
                <p className="text-sm text-muted-foreground">
                  This deal meets all underwriting criteria and has been approved for further review.
                </p>
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </AdminLayout>
  )
}
